const XLSX = require('xlsx');
const wb = XLSX.readFile('店铺产品基本数据.xls');
const ws = wb.Sheets[wb.SheetNames[0]];
const data = XLSX.utils.sheet_to_json(ws, {header: 1});

const headers = data[5];
const products = data.slice(6).filter(r => r[0]);

console.log('总产品数:', products.length);
console.log('用户说店铺共517个产品，差:', 517 - products.length, '个产品未出现在此导出中\\n');

// Check: products with ALL exposure/click metrics = 0 or '-'
const noData = products.filter(r => {
  const searchExp = r[5];
  const searchClick = r[6];
  const visit = r[8]; // 访问人数
  const inquiry = r[9]; // 询盘个数
  const totalExp = r[21]; // 全店曝光
  const mkExp = r[23]; // 营销曝光
  const stdExp = r[25]; // 标准推广曝光
  const allExp = r[27]; // 全站推广曝光
  // All exp are 0 or '-'
  const allZero = [searchExp, searchClick, totalExp, mkExp, stdExp, allExp].every(v => 
    v === 0 || v === '0' || v === '-' || v === '' || v === null || v === undefined
  );
  return allZero;
});

console.log('所有曝光/点击指标全为0的产品:', noData.length);
noData.forEach(r => {
  console.log('  ID:', r[0], '| 名称:', (r[1]||'').substring(0,40), '| 橱窗:', r[2], '| P4P:', r[4]);
});

// Products with zero search exposure + zero marketing exposure
console.log('\\n--- 按条件分组分析 ---');

// Products with search exposure = 0 or '-'
const noSearchExp = products.filter(r => r[5] === 0 || r[5] === '0' || r[5] === '-');
console.log('搜索曝光为0的产品:', noSearchExp.length);

// Products with NO marketing exposure (营销曝光 + 标准推广 + 全站推广 all 0)
const noMktExp = products.filter(r => {
  const mk = r[23]; const std = r[25]; const all = r[27];
  return (mk === 0 || mk === '0' || mk === '-' || mk === '' || mk === null || mk === undefined) &&
         (std === 0 || std === '0' || std === '-' || std === '' || std === null || std === undefined) &&
         (all === 0 || all === '0' || all === '-' || all === '' || all === null || all === undefined);
});
console.log('所有推广曝光为0的产品:', noMktExp.length);

// Products that have at least some data (search exposure > 0 or any marketing exposure)
const hasData = products.filter(r => !noMktExp.includes(r));
console.log('有至少一项推广曝光数据的产品:', hasData.length);

// Among noMktExp, how many have non-zero search exposure?
const noMktButSearch = noMktExp.filter(r => r[5] > 0 || (typeof r[5] === 'string' && r[5] !== '0' && r[5] !== '-'));
console.log('推广曝光为0但有自然搜索曝光:', noMktButSearch.length);
noMktButSearch.forEach(r => {
  console.log('  ID:', r[0], '| 搜索曝光:', r[5], '| 名称:', (r[1]||'').substring(0,40));
});
