const XLSX = require('xlsx');

// Read the main data file
const wb = XLSX.readFile('店铺产品基本数据.xls');
const ws = wb.Sheets[wb.SheetNames[0]];
const data = XLSX.utils.sheet_to_json(ws, {header: 1});
const headers = data[5];
const products = data.slice(6).filter(r => r[0]);

// Products with ZERO marketing exposure
const noMktExp = products.filter(r => {
  const mk = r[23]; const std = r[25]; const all = r[27];
  return (mk === 0 || mk === '0' || mk === '-' || mk === '' || mk === null || mk === undefined) &&
         (std === 0 || std === '0' || std === '-' || std === '' || std === null || std === undefined) &&
         (all === 0 || all === '0' || all === '-' || all === '' || all === null || all === undefined);
});

// Among these, check 是否P4P, 是否橱窗, 是否顶展
console.log('=== 397个零推广曝光产品的特征 ===');
console.log('是否P4P:');
const p4pCounts = {};
noMktExp.forEach(r => { const v = r[4]; p4pCounts[v] = (p4pCounts[v]||0)+1; });
Object.entries(p4pCounts).forEach(([k,v]) => console.log('  P4P=' + k + ':', v));

console.log('是否橱窗:');
const winCounts = {};
noMktExp.forEach(r => { const v = r[2]; winCounts[v] = (winCounts[v]||0)+1; });
Object.entries(winCounts).forEach(([k,v]) => console.log('  橱窗=' + k + ':', v));

console.log('是否顶展:');
const topCounts = {};
noMktExp.forEach(r => { const v = r[3]; topCounts[v] = (topCounts[v]||0)+1; });
Object.entries(topCounts).forEach(([k,v]) => console.log('  顶展=' + k + ':', v));

// Categorize by product type via title keywords
const categories = {
  '连体衣/Romper/Onesie': 0,
  '儿童套装/Kids Set': 0,
  '布尿裤/训练裤/纸尿裤': 0,
  '围兜/Bibs/口水巾': 0,
  '吸汗巾/Saliva': 0,
  '睡袋/抱被/Swaddle': 0,
  '床品/盖毯/Blanket': 0,
  '浴巾/浴袍/Towel': 0,
  '隔尿垫/尿垫': 0,
  '枕头/定型枕': 0,
  '配饰/帽子/袜子/其他': 0,
  '服装/运动套/外套': 0,
  '内衣/保暖/睡衣': 0,
  '裙装/Dress': 0,
};

noMktExp.forEach(r => {
  const title = (r[1]||'').toLowerCase();
  if (title.match(/bib|围兜|口水巾|burp/i)) categories['围兜/Bibs/口水巾']++;
  else if (title.match(/diaper|nappy|布尿裤|训练裤|potty|纸尿裤|training pants/i)) categories['布尿裤/训练裤/纸尿裤']++;
  else if (title.match(/saliva|吸汗巾|方巾|handker/i)) categories['吸汗巾/Saliva']++;
  else if (title.match(/swaddle|睡袋|抱被|sleep sack/i)) categories['睡袋/抱被/Swaddle']++;
  else if (title.match(/blanket|盖毯|床品|quilt|comforter|bedding/i)) categories['床品/盖毯/Blanket']++;
  else if (title.match(/towel|浴巾|浴袍|hooded.*bath/i)) categories['浴巾/浴袍/Towel']++;
  else if (title.match(/pillow|定型枕|枕头/i)) categories['枕头/定型枕']++;
  else if (title.match(/romper|onesie|连体衣|jumpsuit|baby.*suit/i)) categories['连体衣/Romper/Onesie']++;
  else if (title.match(/dress|裙/i)) categories['裙装/Dress']++;
  else if (title.match(/pajama|睡衣|sleepwear|underwear|内衣|thermal/i)) categories['内衣/保暖/睡衣']++;
  else if (title.match(/set|套装|suit|track/i) && title.match(/kids|child|boy|girl|toddler|儿童|婴幼/i)) categories['儿童套装/Kids Set']++;
  else if (title.match(/垫|changing pad|waterproof.*pad/i)) categories['隔尿垫/尿垫']++;
  else categories['配饰/帽子/袜子/其他']++;
});

console.log('\\n产品类别分布:');
Object.entries(categories).filter(([k,v]) => v>0).sort((a,b) => b[1]-a[1]).forEach(([k,v]) => {
  console.log('  ' + k + ':', v);
});

// Also: how many of the 85 with promotion data are current P4P products?
const hasMktExp = products.filter(r => !noMktExp.includes(r));
console.log('\\n=== 85个有推广曝光数据的产品 ===');
const p4pH = {};
hasMktExp.forEach(r => { const v = r[4]; p4pH[v] = (p4pH[v]||0)+1; });
Object.entries(p4pH).forEach(([k,v]) => console.log('  P4P=' + k + ':', v));
