const fs = require('fs');
const path = require('path');
const vaultRoot = 'E:/道友的宝贝/道友的宝贝';

function getAllMdFiles(dir, exclude) {
  let results = [];
  try {
    const list = fs.readdirSync(dir);
    for (const f of list) {
      const fp = path.join(dir, f);
      const stat = fs.statSync(fp);
      if (stat.isDirectory()) {
        if (!exclude.includes(f) && !f.startsWith('.')) {
          results = results.concat(getAllMdFiles(fp, exclude));
        }
      } else if (f.endsWith('.md')) {
        results.push(fp);
      }
    }
  } catch(e) {}
  return results;
}

const allFiles = getAllMdFiles(vaultRoot, ['.obsidian', 'node_modules']);

function extractLinks(content) {
  const links = [];
  const regex = /\[\[([^\]]+)\]\]/g;
  let match;
  while ((match = regex.exec(content)) !== null) {
    const link = match[1].split('|')[0].split('#')[0].trim();
    if (link) links.push(link);
  }
  return links;
}

const outgoing = {};
const incoming = {};

for (const fp of allFiles) {
  const relPath = path.relative(vaultRoot, fp).replace(/\\/g, '/');
  const content = fs.readFileSync(fp, 'utf8');
  const links = extractLinks(content);
  outgoing[relPath] = links;
  if (!incoming[relPath]) incoming[relPath] = [];

  for (const link of links) {
    if (!incoming[link]) incoming[link] = [];
    incoming[link].push(relPath);
  }
}

// 分类报告
const cats = {
  '公司资料': [],
  '店铺推广/P4P': [],
  'AI工具': [],
  'CC对话归档': [],
  'DeepSeek存档': [],
  '根目录/其他': []
};

for (const fp of allFiles) {
  const relPath = path.relative(vaultRoot, fp).replace(/\\/g, '/');
  // 判断是否为存档
  if (relPath.includes('对话归档') || relPath.includes('.claude')) continue;

  const inCnt = (incoming[relPath] || []).filter(f => !f.includes('对话归档')).length;
  const outCnt = outgoing[relPath].length;

  if (inCnt === 0) {
    let cat = '根目录/其他';
    if (relPath.startsWith('公司资料库')) cat = '公司资料';
    else if (relPath.startsWith('店铺推广') || relPath.startsWith('cc的产品')) cat = '店铺推广/P4P';
    else if (relPath.startsWith('AI工具')) cat = 'AI工具';
    cats[cat].push({ file: relPath, outgoing: outCnt });
  }
}

console.log('=== 活跃笔记中的孤立笔记（无人引用） ===\n');

for (const [cat, files] of Object.entries(cats)) {
  if (files.length === 0) continue;
  console.log('【' + cat + '】共 ' + files.length + ' 篇孤立笔记');
  files.sort((a, b) => a.file.localeCompare(b.file));
  files.forEach(f => {
    const name = f.file.split('/').pop();
    console.log('  ├ ' + name + (f.outgoing > 0 ? ' (已有出链' + f.outgoing + '条)' : ' (无出链)'));
  });
  console.log('');
}

// 输出全部活跃文件的链接矩阵（用于后续推荐）
console.log('=== 所有活跃笔记文件名列表 ===\n');
for (const fp of allFiles) {
  const relPath = path.relative(vaultRoot, fp).replace(/\\/g, '/');
  if (relPath.includes('对话归档') || relPath.includes('.claude')) continue;
  const name = relPath.split('/').pop().replace('.md', '');
  const inCnt = (incoming[relPath] || []).length;
  console.log(name + ' | 入链:' + inCnt + ' | ' + relPath);
}
